import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  // Use discover_trending_markets to find the most active markets by 24h volume
  const result = await callMcpSkill({
    toolId: "5cc326fb-500d-4c17-bc5f-ade143210636",
    toolName: "discover_trending_markets",
    args: {
      limit: 10,
      sortBy: "volume_24h"
    }
  });

  return result;
}

